var skillName = "perk.reinforcements";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "RefillSquaddies");
Assert.NotNull(handler, $"Should find RefillSquaddies EventHandler");
handler

var fieldValue = handler.OnlyRefillOnCombatStart;
Assert.NotNull(fieldValue, "OnlyRefillOnCombatStart should be populated");
fieldValue
